                onClick={() => {
                  if (image) {
                    setImage(null);
                    if (fileInputRef.current) {
                      fileInputRef.current.value = '';
                    }
                  } else {
                    triggerFileInput();
                  }
                }}
                size="icon-sm"
                variant="ghost"
              >
                {image ? (
                  <X className="h-4 w-4 text-muted-foreground" />
