            let status: 'complete' | 'current' | 'upcoming' = 'upcoming';
            if (index < activeStep) {
              status = 'complete';
            } else if (index === activeStep) {
              status = 'current';
            }

            return (
              <AccordionItem
                className="!border-b rounded-lg border shadow-xs"
