function DonutChart({ percentage }: { percentage: number }) {
  const backgroundData = [{ name: 'background', value: 100, fill: '#E5E7EB' }];
  const foregroundData = [
    {
      name: 'used',
      value: Math.max(0, Math.min(100, Number(percentage))),
      fill: '#3B82F6',
    },
    {
      name: 'empty',
      value: 100 - Math.max(0, Math.min(100, Number(percentage))),
      fill: 'transparent',
    },
  ];

  return (
    <ChartContainer
      className="aspect-square h-6 w-6 shrink-0"
      config={chartConfig}
    >
      <PieChart>
        <Pie
          cx="50%"
          cy="50%"
          data={backgroundData}
          dataKey="value"
          innerRadius={6}
          isAnimationActive={false}
          nameKey="name"
          outerRadius={10}
        >
          {backgroundData.map((entry, index) => (
            <Cell fill={entry.fill} key={`bg-cell-${index}`} />
          ))}
        </Pie>
        <Pie
          cx="50%"
          cy="50%"
          data={foregroundData}
          dataKey="value"
          endAngle={-270}
          innerRadius={6}
          nameKey="name"
          outerRadius={10}
          startAngle={90}
        >
          {foregroundData.map((entry, index) => (
            <Cell fill={entry.fill} key={`fg-cell-${index}`} />
          ))}
        </Pie>
      </PieChart>
    </ChartContainer>
  );
}

