export default function Table02() {
  const [pendingAction, setPendingAction] = useState<{
    id: string;
    type: TaskActionType;
  } | null>(null);

  const isTaskActionPending = (action: TaskActionType, taskId: string) =>
    pendingAction?.id === taskId && pendingAction.type === action;

  const isTaskBusy = (taskId: string) => pendingAction?.id === taskId;

  const handleAction = (task: Task, actionType: TaskActionType) => {
    setPendingAction({ id: task.id, type: actionType });
    setTimeout(() => {
      setPendingAction(null);
      console.log(`Action "${actionType}" completed for task:`, task.title);
    }, 1000);
  };

  const renderTaskRow = (task: Task) => {
    const busy = isTaskBusy(task.id);
    const startPending = isTaskActionPending('start', task.id);
    const pausePending = isTaskActionPending('pause', task.id);
    const completePending = isTaskActionPending('complete', task.id);
    const deletePending = isTaskActionPending('delete', task.id);

    return (
      <TableRow className="hover:bg-muted/50" key={task.id}>
        <TableCell className="h-16 px-4 font-medium">{task.title}</TableCell>
        <TableCell className="h-16 px-4 text-muted-foreground text-sm">
          {task.assignee}
        </TableCell>
        <TableCell className="h-16 px-4">
          {getStatusBadge(task.status)}
        </TableCell>

        <TableCell className="h-16 px-4 text-muted-foreground text-sm">
          {task.dueDate}
        </TableCell>
        <TableCell className="h-16 max-w-[300px] px-4 text-muted-foreground text-sm">
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger
                render={<span className="block cursor-help truncate" />}
              >
                {task.notes}
              </TooltipTrigger>
              <TooltipContent className="max-w-md">{task.notes}</TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </TableCell>
        <TableCell className="h-16 px-4">
          <TooltipProvider>
            <div className="flex items-center gap-1">
              {(task.status === 'pending' || task.status === 'blocked') && (
                <Tooltip>
                  <TooltipTrigger
                    render={
                      <Button
                        aria-label="Start"
                        className="h-8 w-8"
                        disabled={busy}
                        onClick={() => handleAction(task, 'start')}
                        size="icon"
                        variant="outline"
                      />
                    }
                  >
                    {startPending ? (
                      <Loader2 className="size-4 animate-spin" />
                    ) : (
                      <PlayIcon className="size-4" />
                    )}
                  </TooltipTrigger>
                  <TooltipContent>Start</TooltipContent>
                </Tooltip>
              )}
              {task.status === 'in-progress' && (
                <>
                  <Tooltip>
                    <TooltipTrigger
                      render={
                        <Button
                          aria-label="Pause"
                          className="h-8 w-8"
                          disabled={busy}
                          onClick={() => handleAction(task, 'pause')}
                          size="icon"
                          variant="outline"
                        />
                      }
                    >
                      {pausePending ? (
                        <Loader2 className="size-4 animate-spin" />
                      ) : (
                        <PauseIcon className="size-4" />
                      )}
                    </TooltipTrigger>
                    <TooltipContent>Pause</TooltipContent>
                  </Tooltip>
                  <Tooltip>
                    <TooltipTrigger
                      render={
                        <Button
                          aria-label="Complete"
                          className="h-8 w-8"
                          disabled={busy}
                          onClick={() => handleAction(task, 'complete')}
                          size="icon"
                          variant="outline"
                        />
                      }
                    >
                      {completePending ? (
                        <Loader2 className="size-4 animate-spin" />
                      ) : (
                        <CheckCircle className="size-4" />
                      )}
                    </TooltipTrigger>
                    <TooltipContent>Complete</TooltipContent>
                  </Tooltip>
                </>
              )}
              <Tooltip>
                <TooltipTrigger
                  render={
                    <Button
                      aria-label="Delete"
                      className="h-8 w-8 text-destructive hover:bg-destructive hover:text-white"
                      disabled={busy}
                      onClick={() => handleAction(task, 'delete')}
                      size="icon"
                      variant="outline"
                    />
                  }
                >
                  {deletePending ? (
                    <Loader2 className="size-4 animate-spin" />
                  ) : (
                    <Trash2Icon className="size-4" />
                  )}
                </TooltipTrigger>
                <TooltipContent>Delete</TooltipContent>
              </Tooltip>
              <Tooltip>
                <TooltipTrigger
                  render={
                    <Button
                      aria-label="View details"
                      className="h-8 w-8"
                      disabled={busy}
                      onClick={() => handleAction(task, 'view')}
                      size="icon"
                      variant="outline"
                    />
                  }
                >
                  <FileTextIcon className="size-4" />
                </TooltipTrigger>
                <TooltipContent>View Details</TooltipContent>
              </Tooltip>
            </div>
          </TooltipProvider>
        </TableCell>
      </TableRow>
    );
  };

  return (
    <div className="w-[95%] rounded-lg border bg-card">
      <Table>
        <TableHeader>
          <TableRow className="border-b hover:bg-transparent">
            <TableHead className="h-12 px-4 font-medium">Title</TableHead>
            <TableHead className="h-12 px-4 font-medium">Assignee</TableHead>
            <TableHead className="h-12 w-[120px] px-4 font-medium">
              Status
            </TableHead>

            <TableHead className="h-12 px-4 font-medium">Due Date</TableHead>
            <TableHead className="h-12 px-4 font-medium">Notes</TableHead>
            <TableHead className="h-12 w-[180px] px-4 font-medium">
              Actions
            </TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>{tasks.map(renderTaskRow)}</TableBody>
      </Table>
    </div>
  );
}

