interface AssignedPerson {
  name: string;
  initials: string;
}

interface TaskItem {
  id: string;
  task: string;
  budget: string;
  deadline: string;
  assigned: AssignedPerson[];
  status: string;
}

interface TaskGroup {
  name: string;
  items: TaskItem[];
}

type StatusVariant = 'success' | 'warning' | 'default' | 'secondary';

const avatarColors = [
  'bg-blue-500',
  'bg-purple-500',
  'bg-emerald-500',
  'bg-cyan-500',
  'bg-rose-500',
  'bg-indigo-500',
];

function getAvatarColor(initials: string) {
  const seed = initials
    .split('')
    .reduce((acc, char) => acc + char.charCodeAt(0), 0);
  return avatarColors[seed % avatarColors.length];
}

function AvatarStack({ people }: { people: AssignedPerson[] }) {
  return (
    <div className="-space-x-2 flex">
      {people.map((person, index) => (
        <Avatar
          className={cn(
            'h-6 w-6 border-2 border-background text-[10px]',
            getAvatarColor(person.initials)
          )}
          key={index}
        >
          <AvatarFallback
            className={cn(
              'font-medium text-white',
              getAvatarColor(person.initials)
            )}
          >
            {person.initials}
          </AvatarFallback>
        </Avatar>
      ))}
    </div>
  );
}

const statusStyles: Record<StatusVariant, { badge: string; dot: string }> = {
  success: {
    badge:
