function getStatusVariant(status: string): StatusVariant {
  switch (status) {
    case 'Completed':
      return 'success';
    case 'In Progress':
      return 'default';
    case 'Planning':
      return 'secondary';
    case 'On Hold':
      return 'warning';
    default:
      return 'default';
  }
}

